// CSD_RATIONALE_BEGIN
// Use mostly unconstrained steps for the initial window size, then switch to constrained steps when inside the delimited window.
// After exiting the delimited window or encountering a complete prefix, rollback to a valid prefix.
// This approach balances between unconstrained and constrained generation to ensure the final output is grammatically correct.
// CSD_RATIONALE_END

var delim := new Delimiter(LeftDelimiter, RightDelimiter);
var helpers := new CSDHelpers(lm, parser, delim);
helpers.DelimitersInLMAlways();
var stepsLeft := maxSteps;
var stepCounter := 0;
var hasValid := false;

// Initialize generated as an empty sequence
generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated) && stepCounter < maxSteps
{
    invariant lm.ValidTokensIdsLogits()
    invariant 0 <= stepsLeft <= maxSteps
    invariant |generated| + stepsLeft == maxSteps
    invariant helpers.ConstrainedWindowValid(generated)
    invariant decreases stepsLeft

    var next: Token;
    var newSteps: nat;

    // Perform unconstrained steps for the initial window size
    if (stepCounter < 5 || stepCounter > 20)
    {
        var next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
        generated := generated + [next];
        stepsLeft := newSteps;
    }
    else
    {
        // Check if we are inside the constrained window
        if (helpers.InsideDelimitedWindow(generated) && !parser.IsCompletePrefix(helpers.GetDelimitedContent(generated)))
        {
            // Perform constrained steps within the constrained window
            var next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
            generated := generated + [next];
            stepsLeft := newSteps;
        }
        else
        {
            // If we exit the constrained window or encounter a complete prefix, rollback to a valid prefix
            generated := helpers.RollbackToValidPrefix(generated);
            stepsLeft := maxSteps - |generated|;
        }
    }

    stepCounter := stepCounter + 1;
}

